module top_module(
    input [7:0] obf_A,
    input [7:0] B,
    output reg [7:0] Sum,
    output reg [7:0] Diff,
    output reg [7:0] Prod,
    output reg [7:0] Quot
    );always @* begin
        Sum = obf_A + B;
        Diff = obf_A - B;
        Prod = obf_A * B;
        if (B == 0) begin
            Quot = 8'hFF;
        end else begin
            Quot = obf_A / B;
        end
    end

endmodule
